public static String[] stripAll(final String[] strs, final String stripChars) {
    int strsLen;
    if (strs == null || (strsLen = strs.length) == 0) {
        return strs;
    }
    final String[] newArr = new String[strsLen];
    for (int i = 0; i < strsLen; i++) {
        newArr[i] = strip(strs[i], stripChars);
    }
    return newArr;
}

