public double nextExponential(double mean) {
    if (mean <= 0.0) {
        throw new NotStrictlyPositiveException(LocalizedFormats.MEAN, mean);
    }
    // Step 1:
    double a = 0;
    double u = this.nextUniform(0, 1);
    // Step 2 and 3:
    while (u < 0.5) {
        a += EXPONENTIAL_SA_QI[0];
        u *= 2;
    }
    // Step 4 (now u >= 0.5):
    u += u - 1;
    // Step 5:
    if (u <= EXPONENTIAL_SA_QI[0]) {
        return mean * (a + u);
    }
    // Step 6:
    // Should be 1, be we iterate before it in while using 0
    int i = 0;
    double u2 = this.nextUniform(0, 1);
    double umin = u2;
    // Step 7 and 8:
    do {
        ++i;
        u2 = this.nextUniform(0, 1);
        if (u2 < umin) {
            umin = u2;
        }
        // Step 8:
    } while (// Ensured to exit since EXPONENTIAL_SA_QI[MAX] = 1
    u > EXPONENTIAL_SA_QI[i]);
    return mean * (a + umin * EXPONENTIAL_SA_QI[0]);
}

