public double value(double v) {
    if (v < knots[0] || v >= knots[n]) {
        throw new FunctionEvaluationException(v, "Argument outside domain");
    }
    int i = Arrays.binarySearch(knots, v);
    if (i < 0) {
        i = -i - 2;
    }
    return polynomials[i].value(v - knots[i]);
}

