public static Supplier<T> memoize(Supplier<T> delegate) {
    if (delegate instanceof NonSerializableMemoizingSupplier || delegate instanceof MemoizingSupplier) {
        return delegate;
    }
    return delegate instanceof Serializable ? new MemoizingSupplier<T>(delegate) : new NonSerializableMemoizingSupplier<T>(delegate);
}

public CacheBuilder<K,V> expireAfterAccess(long duration, TimeUnit unit) {
    checkState(expireAfterAccessNanos == UNSET_INT, "expireAfterAccess was already set to %s ns", expireAfterAccessNanos);
    checkArgument(duration >= 0, "duration cannot be negative: %s %s", duration, unit);
    this.expireAfterAccessNanos = unit.toNanos(duration);
    return this;
}

public DiscoveredSolution run(VehicleRoutingProblem vrp, Collection<VehicleRoutingProblemSolution> solutions) {
    VehicleRoutingProblemSolution solution = solutionSelector.selectSolution(solutions);
    if (solution == null)
        throw new IllegalStateException("solution is null. check solutionSelector to return an appropiate solution.");
    VehicleRoutingProblemSolution lastSolution = VehicleRoutingProblemSolution.copyOf(solution);
    for (SearchStrategyModule module : searchStrategyModules) {
        VehicleRoutingProblemSolution newSolution = module.runAndGetSolution(lastSolution);
        lastSolution = newSolution;
